#!/usr/bin/env python3 """Download and register the uncensored roleplay GGUF for local_roleplay tier.""" from __future__ import annotations import json import subprocess import sys from pathlib import Path VAULT_SCRIPTS = Path(r"D:\PhronesisVault\scripts") HERMES_SCRIPTS = Path(__file__).resolve().parent CONFIG_PATH = Path(r"D:\PhronesisVault\Operations\roleplay-subsystem-v0.1.json") GGUF_MAP = Path(r"D:\PhronesisVault\Operations\LlamaCpp-GGUF-Map-v0.1.json") MODELS_INI = Path(r"D:\PhronesisModels\presets\models.ini") MOE_MAP = Path(r"D:\PhronesisVault\Operations\MoE-Task-Type-Map-v0.1.json") def _load_cfg() -> dict: return json.loads(CONFIG_PATH.read_text(encoding="utf-8")) def _download(repo: str, filename: str) -> dict: cmd = [ sys.executable, str(VAULT_SCRIPTS / "model_inventory.py"), "--download", repo, "--file", filename, ] print("EXEC:", " ".join(cmd)) proc = subprocess.run(cmd, capture_output=True, text=True) print(proc.stdout) if proc.returncode != 0: print(proc.stderr, file=sys.stderr) try: return json.loads(proc.stdout.strip().splitlines()[-1]) if proc.stdout.strip() else {"ok": False} except Exception: return {"ok": proc.returncode == 0, "stdout": proc.stdout, "stderr": proc.stderr} def _register_model(path: Path, logical: str, cfg: dict) -> None: model_cfg = cfg.get("model") or {} entry = { "gguf_file": path.name, "path": str(path), "role": "uncensored_roleplay", "latency_budget_ms": 90000, "tier": "local_roleplay", "port": 8090, "storage_tier": "candidate" if "candidates" in str(path) else "current", "uncensored": True, "ctx_size": model_cfg.get("ctx_size", 12288), } if GGUF_MAP.is_file(): data = json.loads(GGUF_MAP.read_text(encoding="utf-8")) data.setdefault("models", {})[logical] = entry data.setdefault("models", {})[path.name] = {**entry, "logical_name": logical} data.setdefault("filename_to_logical", {})[path.name] = logical data["reconciled_at"] = __import__("datetime").datetime.now(__import__("datetime").timezone.utc).isoformat() GGUF_MAP.write_text(json.dumps(data, indent=2), encoding="utf-8") ini_block = ( f"\n[{logical}]\n" f"model = {path}\n" f"ctx-size = {model_cfg.get('ctx_size', 12288)}\n" f"ngl = {model_cfg.get('ngl', 28)}\n" ) if MODELS_INI.is_file(): text = MODELS_INI.read_text(encoding="utf-8") if f"[{logical}]" not in text: MODELS_INI.write_text(text.rstrip() + ini_block, encoding="utf-8") if MOE_MAP.is_file(): moe = json.loads(MOE_MAP.read_text(encoding="utf-8-sig")) ur = moe.setdefault("unified_router", {}) ur.setdefault("tier_logical_models", {})["local_roleplay"] = logical MOE_MAP.write_text(json.dumps(moe, indent=2), encoding="utf-8") def main() -> int: cfg = _load_cfg() m = cfg.get("model") or {} repo = m.get("repo_id") filename = m.get("filename") result = _download(repo, filename) if not result.get("ok"): print("Primary download failed trying fallback...") result = _download(m.get("fallback_repo_id"), m.get("fallback_filename")) if result.get("ok"): cfg["logical_model"] = "llama-3.1-8b-abliterated" CONFIG_PATH.write_text(json.dumps(cfg, indent=2), encoding="utf-8") if not result.get("ok"): print(json.dumps({"status": "download_failed", **result}, indent=2)) return 1 path = Path(result.get("path") or "") if not path.is_file(): candidates = Path(r"D:\PhronesisModels\models\candidates") matches = list(candidates.glob("Rocinante*.gguf")) + list(candidates.glob("*abliterated*.gguf")) path = matches[0] if matches else path logical = cfg.get("logical_model", "rocinante-12b") if "abliterated" in path.name.lower(): logical = "llama-3.1-8b-abliterated" _register_model(path, logical, cfg) print(json.dumps({"status": "provisioned", "path": str(path), "logical_model": logical}, indent=2)) return 0 if __name__ == "__main__": raise SystemExit(main())